@lru_cache(maxsize=None)
def fib(n: int) -> int:
    """
    Returns the nth Fibonacci number using memoization.
    fib(0) = 0, fib(1) = 1.
    """
    if n < 0:
        raise ValueError("n must be a non-negative integer.")
    if n == 0:
        return 0
    if n == 1:
        return 1

    return fib(n - 1) + fib(n - 2)

